// ============================================================================
// PARSE INPUT - Agente Calendario Leraysi
// ============================================================================
// Procesa y valida el input del Master AI Agent
// COMBINA: llm_output (del LLM) + state (de Input Main)
// Calcula duración basada en servicio + complejidad del cabello
// ============================================================================

const raw = $input.first().json;

// ============================================================================
// PASO 1: EXTRAER LLM_OUTPUT Y STATE
// ============================================================================
// El tool debe enviar:
// {
//   "llm_output": {...lo que el LLM extrajo del mensaje...},
//   "state": {...el state completo de Input Main...}
// }

// Extraer llm_output (lo que el LLM extrajo del mensaje del cliente)
const llmOutput = typeof raw.llm_output === 'string'
  ? JSON.parse(raw.llm_output)
  : (raw.llm_output || {});

const state = typeof raw.state === 'string' ? JSON.parse(raw.state) : (raw.state || {});

// ============================================================================
// PASO 2: COMBINAR LLM_OUTPUT + STATE
// ============================================================================
// llmOutput tiene prioridad (datos frescos del mensaje)
// State llena los campos que el LLM no puede extraer

const input = {
  // === Del LLM_OUTPUT (lo que el LLM extrajo del mensaje) ===
  nombre_clienta: llmOutput.nombre_clienta || state.full_name || state.nick_name,
  servicio: llmOutput.servicio || (state.servicio_interes ? [state.servicio_interes] : []),
  fecha_deseada: llmOutput.fecha_deseada || llmOutput.fecha,
  hora_deseada: llmOutput.hora_deseada || llmOutput.hora || null,
  precio: llmOutput.precio || 0,
  email: llmOutput.email || state.email || null,

  // === Del STATE (datos que el LLM no puede ver en el userPrompt) ===
  telefono: state.phone,
  clienta_id: state.lead_id,
  lead_id: state.lead_id,  // Alias para uso en tools
  lead_row_id: state.row_id,
  conversation_id: state.conversation_id,
  image_analysis: state.image_analysis || null,

  // Estado de turno existente (para reprogramación)
  turno_agendado: state.turno_agendado || false,
  turno_fecha: state.turno_fecha || null,

  // Complejidad y largo del cabello (del image_analysis)
  complejidad: state.image_analysis?.complexity || 'media',
  largo_cabello: state.image_analysis?.length || 'medio'
};

// ============================================================================
// CONFIGURACIÓN DE SERVICIOS Y DURACIONES
// ============================================================================
const SERVICIOS_CONFIG = {
  // Servicios livianos (45-60 min base)
  'Peinados': { base_min: 45, categoria: 'liviano' },
  'Manicure': { base_min: 30, categoria: 'liviano' },
  'Pedicure': { base_min: 45, categoria: 'liviano' },
  'Maquillaje': { base_min: 45, categoria: 'liviano' },
  'Corte de cabello': { base_min: 45, categoria: 'liviano' },

  // Servicios pesados (90-120 min base)
  'Alisado': { base_min: 120, categoria: 'pesado' },
  'Keratina': { base_min: 120, categoria: 'pesado' },
  'Botox capilar': { base_min: 90, categoria: 'pesado' },
  'Alisado con keratina': { base_min: 150, categoria: 'muy_pesado' },

  // Servicios de color (60-90 min base)
  'Tinte': { base_min: 90, categoria: 'pesado' },
  'Mechas': { base_min: 120, categoria: 'pesado' },
  'Balayage': { base_min: 150, categoria: 'muy_pesado' },
  'Decoloración': { base_min: 120, categoria: 'pesado' }
};

// Multiplicadores según largo del cabello
const MULTIPLICADOR_LARGO = {
  'corto': 0.8,
  'medio': 1.0,
  'largo': 1.3,
  'muy_largo': 1.5
};

// Multiplicadores según complejidad del trabajo
const MULTIPLICADOR_COMPLEJIDAD = {
  'simple': 0.9,
  'media': 1.0,
  'compleja': 1.2,
  'muy_compleja': 1.4
};

// ============================================================================
// VALIDACIÓN DE CAMPOS REQUERIDOS
// ============================================================================
const camposRequeridos = ['clienta_id', 'nombre_clienta', 'telefono', 'servicio', 'fecha_deseada', 'precio'];
const camposFaltantes = camposRequeridos.filter(campo => !input[campo]);

if (camposFaltantes.length > 0) {
  throw new Error(`[ParseInput] Campos requeridos faltantes: ${camposFaltantes.join(', ')}`);
}

// ============================================================================
// EXTRACCIÓN DE DATOS
// ============================================================================

// Datos de la clienta
const clienta_id = input.clienta_id;
const nombre_clienta = input.nombre_clienta;
const telefono = input.telefono;
const email = input.email || null;

// Datos del turno
const servicio = Array.isArray(input.servicio) ? input.servicio : [input.servicio];
const fecha_deseada = input.fecha_deseada;
const hora_deseada = input.hora_deseada || null;
const precio = Number(input.precio) || 0;

// IDs de contexto
const lead_row_id = input.lead_row_id || input.row_id;
const conversation_id = input.conversation_id || null;

// Análisis de imagen (si existe)
const image_analysis = input.image_analysis || null;
const largo_cabello = image_analysis?.length || input.largo_cabello || 'medio';
const complejidad = image_analysis?.complexity || input.complejidad || 'media';

// ============================================================================
// CÁLCULO DE DURACIÓN ESTIMADA
// ============================================================================
function calcularDuracion(servicios, largo, complejidad) {
  let duracionTotal = 0;

  for (const srv of servicios) {
    const config = SERVICIOS_CONFIG[srv];
    if (config) {
      duracionTotal += config.base_min;
    } else {
      // Servicio no mapeado, usar 60 min por defecto
      duracionTotal += 60;
    }
  }

  // Aplicar multiplicadores
  const multLargo = MULTIPLICADOR_LARGO[largo] || 1.0;
  const multComplejidad = MULTIPLICADOR_COMPLEJIDAD[complejidad] || 1.0;

  duracionTotal = Math.round(duracionTotal * multLargo * multComplejidad);

  // Redondear a múltiplos de 15 minutos
  return Math.ceil(duracionTotal / 15) * 15;
}

// Determinar categoría más pesada del servicio
function obtenerCategoriaPesada(servicios) {
  const categorias = servicios.map(srv => {
    const config = SERVICIOS_CONFIG[srv];
    return config?.categoria || 'liviano';
  });

  if (categorias.includes('muy_pesado')) return 'muy_pesado';
  if (categorias.includes('pesado')) return 'pesado';
  return 'liviano';
}

const duracion_estimada = calcularDuracion(servicio, largo_cabello, complejidad);
const categoria_servicio = obtenerCategoriaPesada(servicio);
const servicio_detalle = servicio.join(' + ');

// ============================================================================
// OUTPUT
// ============================================================================
return [{
  json: {
    // Datos de la clienta
    clienta_id,
    nombre_clienta,
    telefono,
    email,

    // Datos del turno
    servicio,
    servicio_detalle,
    fecha_deseada,
    hora_deseada,
    precio,
    duracion_estimada,
    categoria_servicio,

    // Análisis de imagen
    image_analysis,
    largo_cabello,
    complejidad,

    // IDs de contexto
    lead_id: input.lead_id,
    lead_row_id,
    conversation_id,

    // Estado de turno (para reprogramación)
    turno_agendado: input.turno_agendado,
    turno_fecha: input.turno_fecha,

    // Metadata
    received_at: new Date().toISOString()
  }
}];

// ============================================================================
// PARSE AGENT RESPONSE - Agente Calendario Leraysi
// ============================================================================
// Parsea la respuesta del agente y mapea al formato del workflow
// Compatible con el nuevo formato determinístico de la LLM
// ============================================================================

const input = $('AnalizarDisponibilidad').first().json;
const agentOutput = $input.first().json.output;

// ============================================================================
// PARSEAR JSON DE LA RESPUESTA (robusto)
// ============================================================================
function extractJSON(text) {
  // Intento directo
  try {
    return JSON.parse(text);
  } catch (e) {}

  // Limpiar markdown code blocks
  let cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {}

  // Buscar JSON embebido
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      return JSON.parse(jsonMatch[0]);
    } catch (e) {}
  }

  // Fallback de error
  return {
    estado: "error",
    mensaje_para_clienta: "Error procesando la solicitud de turno"
  };
}

const llmResponse = extractJSON(agentOutput);

// ============================================================================
// MAPEO DE ESTADO → ACCION (compatibilidad con nodos downstream)
// ============================================================================
const ESTADO_A_ACCION = {
  'turno_creado': 'turno_creado',
  'fecha_no_disponible': 'sin_disponibilidad',
  'turno_reprogramado': 'turno_reprogramado',
  'error': 'error'
};

const accion = ESTADO_A_ACCION[llmResponse.estado] || llmResponse.estado || 'error';

// ============================================================================
// EXTRAER DATOS SEGÚN EL CASO
// ============================================================================
let resultado = {
  // === Datos de contexto (vienen de AnalizarDisponibilidad) ===
  clienta_id: input.clienta_id,
  nombre_clienta: input.nombre_clienta,
  telefono: input.telefono,
  email: input.email || '',
  lead_row_id: input.lead_row_id,
  conversation_id: input.conversation_id || null,
  precio: input.precio,
  servicio: input.servicio,
  servicio_detalle: input.servicio_detalle || '',

  // === Decisión del agente (mapeada) ===
  accion: accion,
  mensaje_para_clienta: llmResponse.mensaje_para_clienta,
  alternativas: llmResponse.alternativas || []
};

// ============================================================================
// CASO: TURNO CREADO
// ============================================================================
if (llmResponse.estado === 'turno_creado') {
  // Extraer mp_preference_id del link_pago
  const mpPreferenceId = llmResponse.link_pago
    ? (llmResponse.link_pago.match(/pref_id=([^&\s]+)/)?.[1] || '')
    : '';

  // Extraer fecha y hora de fecha_hora (formato "YYYY-MM-DD HH:MM")
  const [fechaTurno, horaTurno] = (llmResponse.fecha_hora || '').split(' ');

  resultado = {
    ...resultado,
    // Datos del turno
    fecha_turno: fechaTurno || input.fecha_solicitada,
    hora_sugerida: horaTurno || input.hora_deseada || '09:00',

    // IDs de Odoo
    odoo_turno_id: llmResponse.turno_id,

    // MercadoPago
    mp_preference_id: mpPreferenceId,
    link_pago: llmResponse.link_pago || '',

    // Estado y montos
    estado_turno: 'pendiente_pago',
    sena_monto: llmResponse.sena || Math.round((input.precio || 0) * 0.30)
  };
}

// ============================================================================
// CASO: FECHA NO DISPONIBLE
// ============================================================================
if (llmResponse.estado === 'fecha_no_disponible') {
  resultado = {
    ...resultado,
    fecha_solicitada: llmResponse.fecha_solicitada || input.fecha_solicitada,
    motivo_no_disponible: llmResponse.motivo
  };
}

// ============================================================================
// CASO: TURNO REPROGRAMADO
// ============================================================================
if (llmResponse.estado === 'turno_reprogramado') {
  // Extraer fecha y hora nueva (formato "YYYY-MM-DD HH:MM")
  const [fechaNueva, horaNueva] = (llmResponse.fecha_hora_nueva || '').split(' ');

  // Extraer mp_preference_id si hay nuevo link_pago (caso pendiente_pago reprogramado)
  const mpPreferenceId = llmResponse.link_pago
    ? (llmResponse.link_pago.match(/pref_id=([^&\s]+)/)?.[1] || '')
    : '';

  resultado = {
    ...resultado,
    // Datos del turno reprogramado
    // odoo_turno_id viene directamente del LLM (ya calculado según turno_id_nuevo o turno_id_anterior)
    odoo_turno_id: llmResponse.odoo_turno_id,
    turno_id_anterior: llmResponse.turno_id_anterior,
    turno_id_nuevo: llmResponse.turno_id_nuevo,
    fecha_turno: fechaNueva,
    hora_sugerida: horaNueva || '09:00',
    fecha_hora_anterior: llmResponse.fecha_hora_anterior,
    fecha_hora_nueva: llmResponse.fecha_hora_nueva,
    // Para caso pendiente_pago reprogramado (nuevo link de pago)
    mp_preference_id: mpPreferenceId,
    link_pago: llmResponse.link_pago || null,
    // Flags
    calendario_actualizado: true, // Si llegamos aquí, el MCP ya actualizó calendario
    motivo_reprogramacion: llmResponse.motivo || 'Solicitud de la clienta'
  };
}

// ============================================================================
// OUTPUT
// ============================================================================
return [{
  json: resultado
}];

// ============================================================================
// BUILD AGENT PROMPT - Construye el User Message para Agente Calendario
// ============================================================================
// INPUT: Datos combinados de ParseInput + AnalizarDisponibilidad
// OUTPUT: userMessage para el AI Agent del calendario
//
// DISEÑO: 100% determinístico - el agente solo ejecuta y mapea datos
// ============================================================================

const data = $input.first().json;

// ============================================================================
// VALORES PRE-CALCULADOS
// ============================================================================
// Extraer fecha y hora de fecha_solicitada (soporta ISO "2026-01-26T16:00:00" o "2026-01-26 16:00")
const fechaSolicitadaRaw = data.fecha_solicitada || '';
const fechaSoloParte = fechaSolicitadaRaw.includes('T')
  ? fechaSolicitadaRaw.split('T')[0]
  : fechaSolicitadaRaw.split(' ')[0];
const horaSolicitadaParte = fechaSolicitadaRaw.includes('T')
  ? fechaSolicitadaRaw.split('T')[1]?.slice(0, 5)
  : fechaSolicitadaRaw.split(' ')[1]?.slice(0, 5);

// Usar hora de la fecha solicitada, o la hora_deseada del input, o default 09:00
const horaDeseada = horaSolicitadaParte || data.hora_deseada || '09:00';
const duracionHoras = Math.ceil((data.duracion_estimada || 60) / 60);
const senaCalculada = Math.round((data.precio || 0) * 0.3);
// Formato correcto: "2026-01-26 16:00" (fecha espacio hora)
const fechaHoraCompleta = `${fechaSoloParte} ${horaDeseada}`;

// Formatear fecha para mensaje humano (ej: "miércoles 29 de enero")
const formatearFechaHumana = (fechaStr) => {
  if (!fechaStr) return 'fecha no especificada';
  // Extraer solo la parte de la fecha si viene con hora
  const soloFecha = fechaStr.includes('T')
    ? fechaStr.split('T')[0]
    : fechaStr.split(' ')[0];
  const fecha = new Date(soloFecha + 'T12:00:00');
  if (isNaN(fecha.getTime())) return 'fecha inválida';
  const dias = ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'];
  const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio',
                 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
  return `${dias[fecha.getDay()]} ${fecha.getDate()} de ${meses[fecha.getMonth()]}`;
};

const fechaHumana = formatearFechaHumana(data.fecha_solicitada);
const servicioDisplay = data.servicio_detalle || data.servicio || 'servicio';

// ============================================================================
// DETECTAR SI ES REPROGRAMACIÓN
// ============================================================================
const esReprogramacion = data.turno_agendado === true;

// ============================================================================
// CASO 0: REPROGRAMAR TURNO EXISTENTE
// ============================================================================
let instruccionTarea = '';
let jsonRespuestaEsperada = '';

if (esReprogramacion && data.fecha_disponible) {
  const mensajeClientaReprogramado = `¡Listo ${data.nombre_clienta || 'reina'}! Tu turno fue reprogramado para el ${fechaHumana} a las ${horaDeseada}. Te enviamos un email de confirmación.`;

  instruccionTarea = `## 🔄 REPROGRAMAR TURNO

### PASO 1: Llamar a la tool \`leraysi_reprogramar_turno\`

Usar EXACTAMENTE estos parámetros:

\`\`\`json
{
  "lead_id": ${data.lead_id || 'null'},
  "nueva_fecha_hora": "${fechaHoraCompleta}",
  "motivo": "Solicitud de la clienta"
}
\`\`\`

### PASO 2: Después de llamar la tool, responder con este JSON

Reemplazar los valores {ENTRE_LLAVES} con los datos de la respuesta de la tool:

\`\`\`json
{
  "estado": "turno_reprogramado",
  "odoo_turno_id": {turno_id_nuevo de la respuesta si existe, sino turno_id_anterior},
  "turno_id_anterior": {turno_id_anterior de la respuesta},
  "turno_id_nuevo": {turno_id_nuevo de la respuesta o null},
  "lead_id": ${data.lead_id || 'null'},
  "fecha_hora_anterior": "{fecha_hora_anterior de la respuesta}",
  "fecha_hora_nueva": "${fechaHoraCompleta}",
  "servicio": "${data.servicio || 'otro'}",
  "link_pago": "{link_pago de la respuesta si existe, o null}",
  "mensaje_para_clienta": "${mensajeClientaReprogramado}"
}
\`\`\`

**IMPORTANTE:** El campo \`odoo_turno_id\` debe ser el ID del turno activo:
- Si la respuesta tiene \`turno_id_nuevo\` (caso pendiente_pago): usar ese valor
- Si \`turno_id_nuevo\` es null (caso confirmado): usar \`turno_id_anterior\`

**NOTA:** Si la respuesta incluye \`link_pago\`, actualizar el mensaje para incluir: "Necesitás pagar la nueva seña en: {link_pago}"`;

// ============================================================================
// CASO 1: FECHA DISPONIBLE - Crear turno nuevo
// ============================================================================
} else if (data.fecha_disponible) {
  // Pre-construir el mensaje para la clienta (template)
  const mensajeClientaTemplate = `¡Listo ${data.nombre_clienta || 'reina'}! Tu turno de ${servicioDisplay.toLowerCase()} está reservado para el ${fechaHumana} a las ${horaDeseada}. Para confirmarlo, pagá la seña de $${senaCalculada.toLocaleString('es-AR')} en este link: {LINK_PAGO}`;

  instruccionTarea = `## ✅ FECHA DISPONIBLE - CREAR TURNO

### PASO 1: Llamar a la tool \`leraysi_crear_turno\`

Usar EXACTAMENTE estos parámetros:

\`\`\`json
{
  "clienta": "${data.nombre_clienta || ''}",
  "telefono": "${data.telefono || ''}",
  "servicio": "${data.servicio || 'otro'}",
  "fecha_hora": "${fechaHoraCompleta}",
  "precio": ${data.precio || 0},
  "duracion": ${duracionHoras},
  "lead_id": ${data.lead_id || 'null'}${data.email ? `,\n  "email": "${data.email}"` : ''}${data.servicio_detalle ? `,\n  "servicio_detalle": "${data.servicio_detalle}"` : ''}
}
\`\`\`

### PASO 2: Después de llamar la tool, responder con este JSON

Reemplazar los valores {ENTRE_LLAVES} con los datos de la respuesta de la tool:

\`\`\`json
{
  "estado": "turno_creado",
  "turno_id": {turnoId de la respuesta},
  "lead_id": ${data.lead_id || 'null'},
  "fecha_hora": "${fechaHoraCompleta}",
  "servicio": "${data.servicio || 'otro'}",
  "servicio_detalle": "${servicioDisplay}",
  "precio": ${data.precio || 0},
  "sena": {sena de la respuesta},
  "link_pago": "{link_pago de la respuesta}",
  "mensaje_para_clienta": "${mensajeClientaTemplate}"
}
\`\`\`

**IMPORTANTE:** En "mensaje_para_clienta", reemplazar {LINK_PAGO} con el link_pago real de la respuesta.`;

// ============================================================================
// CASO 2: FECHA NO DISPONIBLE - Responder alternativas
// ============================================================================
} else {
  const alternativasTexto = data.alternativas?.length > 0
    ? data.alternativas.map(a => `${a.nombre_dia} ${a.fecha}`).join(', ')
    : 'No hay disponibilidad esta semana';

  const alternativasArray = data.alternativas?.map(a => `"${a.nombre_dia} ${a.fecha}"`) || [];

  const mensajeClientaNoDisponible = `Disculpá, el ${fechaHumana} no tenemos disponibilidad (${(data.motivo_no_disponible || 'agenda completa').toLowerCase()}). Te puedo ofrecer: ${alternativasTexto}. ¿Cuál te queda mejor?`;

  instruccionTarea = `## ❌ FECHA NO DISPONIBLE

**NO llamar ninguna tool.**

Responder ÚNICAMENTE con este JSON (copiarlo exacto):

\`\`\`json
{
  "estado": "fecha_no_disponible",
  "fecha_solicitada": "${data.fecha_solicitada}",
  "motivo": "${data.motivo_no_disponible || 'Sin disponibilidad'}",
  "alternativas": [${alternativasArray.join(', ')}],
  "mensaje_para_clienta": "${mensajeClientaNoDisponible}"
}
\`\`\``;
}

// ============================================================================
// CONSTRUIR MENSAJE COMPLETO
// ============================================================================
const userMessage = `# SOLICITUD DE TURNO - Estilos Leraysi

## Datos de la Solicitud

| Campo | Valor |
|-------|-------|
| **Clienta** | ${data.nombre_clienta || 'No proporcionado'} |
| **Teléfono** | ${data.telefono || 'No proporcionado'} |
| **Email** | ${data.email || 'No proporcionado'} |
| **Lead ID** | ${data.lead_id || 'N/A'} |
| **Servicio** | ${servicioDisplay} |
| **Categoría** | ${data.categoria_servicio || 'No clasificado'} |
| **Duración** | ${data.duracion_estimada || 60} min (${duracionHoras}h) |
| **Precio** | $${(data.precio || 0).toLocaleString('es-AR')} |
| **Seña (30%)** | $${senaCalculada.toLocaleString('es-AR')} |
| **Fecha solicitada** | ${data.fecha_solicitada} (${fechaHumana}) |
| **Hora** | ${horaDeseada} |
| **Disponibilidad** | ${data.fecha_disponible ? '✅ DISPONIBLE' : '❌ NO DISPONIBLE'} |

## Disponibilidad de la Semana

${data.resumen_disponibilidad || 'No disponible'}

---

${instruccionTarea}`;

// ============================================================================
// RETORNAR
// ============================================================================
return [{
  json: {
    ...data,
    userMessage,
    // Datos pre-calculados para uso posterior
    _precalculado: {
      hora: horaDeseada,
      duracion_horas: duracionHoras,
      sena: senaCalculada,
      fecha_hora_completa: fechaHoraCompleta,
      fecha_humana: fechaHumana,
      servicio_display: servicioDisplay
    }
  }
}];

// ============================================================================
// PREPARAR TURNO BASEROW - Agente Calendario Leraysi
// ============================================================================
// Transforma datos de ParseAgentResponse al formato de TurnosLeraysi
// Campos según TABLA-TURNOS-LERAYSI.md
// ============================================================================
// NODO: PrepararTurnoBaserow (Code)
// INPUT: ParseAgentResponse via IF_Agendar (True Branch)
// OUTPUT: Campos listos para Baserow Create Row
// ============================================================================

const data = $input.first().json;

// ============================================================================
// CONFIGURACIÓN
// ============================================================================
const CONFIG = {
  expiracion_minutos: 120 // 2 horas para pagar la seña
};

// Calcular timestamps
const ahora = new Date();
const expiraAt = new Date(ahora.getTime() + CONFIG.expiracion_minutos * 60 * 1000);

// Formatear fecha para Baserow API: ISO 8601 con timezone Argentina
function formatBaserowDatetime(date) {
  // Ajustar UTC a Argentina (UTC-3)
  const argentinaTime = new Date(date.getTime() - (3 * 60 * 60 * 1000));
  const offset = '-03:00';
  const year = argentinaTime.getUTCFullYear();
  const month = String(argentinaTime.getUTCMonth() + 1).padStart(2, '0');
  const day = String(argentinaTime.getUTCDate()).padStart(2, '0');
  const hours = String(argentinaTime.getUTCHours()).padStart(2, '0');
  const minutes = String(argentinaTime.getUTCMinutes()).padStart(2, '0');
  const seconds = String(argentinaTime.getUTCSeconds()).padStart(2, '0');
  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
}

// ============================================================================
// CONSTRUIR REGISTRO PARA BASEROW (TurnosLeraysi)
// ============================================================================
const turnoBaserow = {
  // === Fecha y Hora ===
  fecha: data.fecha_turno,
  hora: data.hora_sugerida || '09:00',

  // === Relación con Lead ===
  clienta_id: data.lead_row_id ? [data.lead_row_id] : [],

  // === Datos de la Clienta (desnormalizados) ===
  nombre_clienta: data.nombre_clienta,
  telefono: data.telefono,
  email: data.email || '',

  // === Servicio ===
  servicio: Array.isArray(data.servicio) ? data.servicio : [data.servicio],
  servicio_detalle: data.servicio_detalle || '',
  tipo_servicio: data.tipo_servicio || 'medio',
  // duracion_min se agrega condicionalmente abajo

  // === Precio y Seña ===
  // precio y sena_monto se agregan condicionalmente abajo
  sena_pagada: false,

  // === Estado ===
  estado: data.estado_turno || 'pendiente_pago',

  // === Mercado Pago ===
  mp_preference_id: data.mp_preference_id || '',
  mp_link: data.link_pago || '',
  mp_payment_id: '', // Se llena cuando se confirma el pago

  // === Timestamps ===
  created_at: formatBaserowDatetime(ahora),
  expira_at: formatBaserowDatetime(expiraAt),
  // confirmado_at se agrega solo cuando tiene valor (ver abajo)

  // === Notas ===
  notas: `Turno creado via chatbot. Servicio: ${data.servicio}`
};

// Agregar campos numéricos solo si tienen valor (Baserow no acepta null)
turnoBaserow.duracion_min = data.duracion_min || 90; // default 90 minutos
if (data.precio != null) {
  turnoBaserow.precio = data.precio;
}
if (data.sena_monto != null) {
  turnoBaserow.sena_monto = data.sena_monto;
}
if (data.odoo_turno_id) {
  turnoBaserow.odoo_turno_id = data.odoo_turno_id;
}
if (data.conversation_id) {
  turnoBaserow.conversation_id = data.conversation_id;
}

// ============================================================================
// OUTPUT
// ============================================================================
return [{
  json: {
    // Campos para Baserow (directo)
    ...turnoBaserow,

    // Preservar datos para FormatearRespuestaExito
    _meta: {
      accion: data.accion,
      mensaje_para_clienta: data.mensaje_para_clienta,
      lead_row_id: data.lead_row_id
    }
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA EXITO - Agente Calendario Leraysi
// ============================================================================
// Construye la respuesta final exitosa para devolver al Master Agent
// ============================================================================
// NODO: FormatearRespuestaExito (Code)
// INPUT: CrearTurnoBaserow (respuesta de Baserow con ID del row creado)
// OUTPUT: Respuesta estructurada para Return
// ============================================================================

const baserowResponse = $input.first().json;

// Recuperar metadata del nodo anterior (PrepararTurnoBaserow)
const metaData = $('PrepararTurnoBaserow').first().json._meta;

// El ID del turno creado en Baserow
const turnoRowId = baserowResponse.id;

// ============================================================================
// OUTPUT PARA MASTER AGENT
// ============================================================================
return [{
  json: {
    success: true,
    accion: metaData.accion,
    turno_id: turnoRowId,
    mensaje_para_clienta: metaData.mensaje_para_clienta,
    lead_row_id: metaData.lead_row_id
  }
}];

// ============================================================================
// ANALIZAR DISPONIBILIDAD - Agente Calendario Leraysi
// ============================================================================
// INPUT: ParseInput (datos del turno) + GetTurnosSemana (turnos existentes)
// OUTPUT: Disponibilidad calculada + alternativas pre-calculadas si no hay cupo
// ============================================================================

// Obtener turnos (puede ser array vacío)
const turnosRaw = $('GetTurnosSemana').all();
const turnos = turnosRaw.length > 0 ? turnosRaw.map(item => item.json) : [];

const input = $('ParseInput').first().json;

// Configuración de capacidad máxima por día
const CAPACIDAD = {
  max_pesados: 2,
  max_muy_pesados: 1,
  max_turnos_dia: 6
};

// Agrupar turnos por fecha
const turnosPorDia = {};

turnos.forEach(turno => {
  const fecha = turno.fecha?.split('T')[0];
  if (!fecha) return;

  if (!turnosPorDia[fecha]) {
    turnosPorDia[fecha] = {
      fecha,
      turnos: [],
      count_total: 0,
      count_liviano: 0,
      count_medio: 0,
      count_pesado: 0,
      count_muy_pesado: 0,
      duracion_total: 0
    };
  }

  turnosPorDia[fecha].turnos.push(turno);
  turnosPorDia[fecha].count_total++;
  turnosPorDia[fecha].duracion_total += turno.duracion_min || 0;

  const tipo = turno.tipo_servicio?.value || turno.tipo_servicio || 'medio';
  if (tipo === 'liviano') turnosPorDia[fecha].count_liviano++;
  else if (tipo === 'medio') turnosPorDia[fecha].count_medio++;
  else if (tipo === 'pesado') turnosPorDia[fecha].count_pesado++;
  else if (tipo === 'muy_pesado') turnosPorDia[fecha].count_muy_pesado++;
});

// Generar próximos 7 días con disponibilidad
const dias = [];
const hoy = new Date();

for (let i = 0; i < 7; i++) {
  const fecha = new Date(hoy);
  fecha.setDate(hoy.getDate() + i);
  const fechaStr = fecha.toISOString().split('T')[0];

  const diaSemana = fecha.getDay();
  const nombreDia = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'][diaSemana];

  // Domingo cerrado
  if (diaSemana === 0) {
    dias.push({
      fecha: fechaStr,
      nombre_dia: nombreDia,
      abierto: false,
      disponible: false,
      motivo: 'Cerrado'
    });
    continue;
  }

  const datosDia = turnosPorDia[fechaStr] || {
    count_total: 0,
    count_pesado: 0,
    count_muy_pesado: 0,
    duracion_total: 0
  };

  const pesadosOcupados = datosDia.count_pesado + datosDia.count_muy_pesado;
  const puedeRecibirPesado = pesadosOcupados < CAPACIDAD.max_pesados;
  const puedeRecibirMuyPesado = datosDia.count_muy_pesado < CAPACIDAD.max_muy_pesados;
  const puedeRecibirMas = datosDia.count_total < CAPACIDAD.max_turnos_dia;

  const cargaPorcentaje = Math.round((datosDia.duracion_total / 480) * 100);

  dias.push({
    fecha: fechaStr,
    nombre_dia: nombreDia,
    abierto: true,
    turnos_agendados: datosDia.count_total,
    pesados_agendados: pesadosOcupados,
    duracion_total_min: datosDia.duracion_total,
    carga_porcentaje: cargaPorcentaje,
    puede_recibir_pesado: puedeRecibirPesado,
    puede_recibir_muy_pesado: puedeRecibirMuyPesado,
    puede_recibir_turno: puedeRecibirMas,
    disponible: puedeRecibirMas
  });
}

// ============================================================================
// VERIFICAR DISPONIBILIDAD DEL DÍA SOLICITADO Y GENERAR ALTERNATIVAS
// ============================================================================
// Extraer solo la fecha (sin hora) para comparación - soporta ISO con T o solo fecha
const fechaSolicitadaRaw = input.fecha_deseada || '';
const fechaSolicitada = fechaSolicitadaRaw.includes('T')
  ? fechaSolicitadaRaw.split('T')[0]
  : fechaSolicitadaRaw.split(' ')[0];
const diaSolicitado = dias.find(d => d.fecha === fechaSolicitada);

// Determinar si la fecha está disponible
const fechaDisponible = diaSolicitado?.abierto && diaSolicitado?.disponible;

// Pre-calcular alternativas si el día NO está disponible
let alternativas = [];
let motivoNoDisponible = null;

if (!fechaDisponible) {
  // Determinar el motivo
  if (!diaSolicitado) {
    motivoNoDisponible = 'Fecha fuera de rango (solo se pueden agendar turnos en los próximos 7 días)';
  } else if (!diaSolicitado.abierto) {
    motivoNoDisponible = 'Cerrado (Domingo)';
  } else if (!diaSolicitado.disponible) {
    motivoNoDisponible = `Agenda llena (${diaSolicitado.turnos_agendados} turnos, ${diaSolicitado.carga_porcentaje}% de capacidad)`;
  }

  // Buscar los próximos 3 días disponibles como alternativas
  alternativas = dias
    .filter(d => d.abierto && d.disponible)
    .slice(0, 3)
    .map(d => ({
      fecha: d.fecha,
      nombre_dia: d.nombre_dia,
      turnos_agendados: d.turnos_agendados,
      carga_porcentaje: d.carga_porcentaje
    }));
}

// Resumen para el agente
const resumen = dias
  .filter(d => d.abierto)
  .map(d => {
    let estado = '';
    if (!d.disponible) estado = '❌ Lleno';
    else if (d.carga_porcentaje >= 70) estado = '⚠️ Casi lleno';
    else if (d.carga_porcentaje >= 40) estado = '📅 Moderado';
    else estado = '✅ Disponible';

    return `${d.nombre_dia} ${d.fecha}: ${estado} (${d.turnos_agendados} turnos, ${d.carga_porcentaje}% carga)`;
  })
  .join('\n');

return [{
  json: {
    ...input,
    disponibilidad: dias,
    resumen_disponibilidad: resumen,
    capacidad_config: CAPACIDAD,
    turnos_existentes: turnos.length,
    // Nuevos campos para el agente
    // Mantener fecha original completa (con hora si viene) para BuildAgentPrompt
    fecha_solicitada: fechaSolicitadaRaw,
    fecha_disponible: fechaDisponible,
    motivo_no_disponible: motivoNoDisponible,
    alternativas: alternativas
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA SIN DISPONIBILIDAD - Agente Calendario Leraysi
// ============================================================================
// Formatea la respuesta cuando no hay disponibilidad para el turno solicitado
// ============================================================================
// NODO: FormatearRespuestaSinDisponibilidad (Code)
// INPUT: ParseAgentResponse via IF_Agendar (False Branch)
// OUTPUT: Respuesta formateada para el workflow principal
// ============================================================================

const data = $input.first().json;

// ============================================================================
// OUTPUT
// ============================================================================

return [{
  json: {
    success: false,
    accion: data.accion || 'sin_disponibilidad',
    mensaje_para_clienta: data.mensaje_para_clienta,
    lead_row_id: data.lead_row_id,
    alternativas: data.alternativas || []
  }
}];

// ============================================================================
// PREPARAR REPROGRAMADO BASEROW - Agente Calendario Leraysi
// ============================================================================
// Transforma datos para UPDATE en Baserow
// INPUT: BuscarTurnoBaserow (resultado de búsqueda con row_id)
// OUTPUT: Campos listos para Baserow Update Row
// ============================================================================
// NODO: PrepararReprogramadoBaserow (Code)
// FLUJO: Switch → BuscarTurnoBaserow → PrepararReprogramadoBaserow → Update
// ============================================================================

// Datos del turno encontrado en Baserow (viene de BuscarTurnoBaserow)
const turnoEncontrado = $input.first().json;

// Datos de ParseAgentResponse
const data = $('ParseAgentResponse').first().json;

// ============================================================================
// VALIDACIÓN
// ============================================================================
if (!turnoEncontrado || !turnoEncontrado.id) {
  throw new Error('[PrepararReprogramadoBaserow] No se encontró el turno en Baserow. ' +
                  `odoo_turno_id buscado: ${data.odoo_turno_id}`);
}

const turnoRowId = turnoEncontrado.id;

// ============================================================================
// FORMATEAR FECHA
// ============================================================================
function formatBaserowDatetime(date) {
  const argentinaTime = new Date(date.getTime() - (3 * 60 * 60 * 1000));
  const offset = '-03:00';
  const year = argentinaTime.getUTCFullYear();
  const month = String(argentinaTime.getUTCMonth() + 1).padStart(2, '0');
  const day = String(argentinaTime.getUTCDate()).padStart(2, '0');
  const hours = String(argentinaTime.getUTCHours()).padStart(2, '0');
  const minutes = String(argentinaTime.getUTCMinutes()).padStart(2, '0');
  const seconds = String(argentinaTime.getUTCSeconds()).padStart(2, '0');
  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
}

const ahora = new Date();

// ============================================================================
// CAMPOS A ACTUALIZAR EN BASEROW
// ============================================================================
const updateFields = {
  // Nueva fecha y hora
  fecha: data.fecha_turno,
  hora: data.hora_sugerida || '09:00',

  // Actualizar odoo_turno_id (puede ser nuevo si era pendiente_pago)
  odoo_turno_id: data.odoo_turno_id,

  // Timestamp de actualización
  updated_at: formatBaserowDatetime(ahora),

  // Notas con historial
  notas: `Turno reprogramado el ${ahora.toLocaleDateString('es-AR')}. ` +
         `Fecha anterior: ${data.fecha_hora_anterior || 'N/A'}. ` +
         `Motivo: ${data.motivo_reprogramacion || 'No especificado'}`
};

// Si hay link_pago nuevo (caso pendiente_pago → nuevo turno)
if (data.link_pago) {
  updateFields.mp_link = data.link_pago;
  updateFields.mp_preference_id = data.mp_preference_id || '';
}

// ============================================================================
// OUTPUT
// ============================================================================
return [{
  json: {
    // Row ID para el Update
    row_id: turnoRowId,

    // Campos para Baserow Update
    ...updateFields,

    // Metadata para FormatearRespuestaReprogramado
    _meta: {
      accion: data.accion,
      mensaje_para_clienta: data.mensaje_para_clienta,
      lead_row_id: data.lead_row_id,
      fecha_hora_anterior: data.fecha_hora_anterior,
      fecha_hora_nueva: data.fecha_hora_nueva,
      calendario_actualizado: data.calendario_actualizado
    }
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA REPROGRAMADO - Agente Calendario Leraysi
// ============================================================================
// Construye la respuesta final para turno reprogramado
// ============================================================================
// NODO: FormatearRespuestaReprogramado (Code)
// INPUT: ActualizarTurnoBaserow (respuesta de Baserow Update)
// OUTPUT: Respuesta estructurada para Return
// ============================================================================

const baserowResponse = $input.first().json;

// Recuperar metadata del nodo anterior (PrepararReprogramadoBaserow)
const metaData = $('PrepararReprogramadoBaserow').first().json._meta;

// El ID del turno actualizado en Baserow
const turnoRowId = baserowResponse.id;

// ============================================================================
// OUTPUT PARA MASTER AGENT
// ============================================================================
return [{
  json: {
    success: true,
    accion: metaData.accion,
    turno_id: turnoRowId,
    mensaje_para_clienta: metaData.mensaje_para_clienta,
    lead_row_id: metaData.lead_row_id,

    // Datos específicos de reprogramación
    reprogramacion: {
      fecha_hora_anterior: metaData.fecha_hora_anterior,
      fecha_hora_nueva: metaData.fecha_hora_nueva,
      calendario_actualizado: metaData.calendario_actualizado
    }
  }
}];

// ============================================================================
// FORMATEAR RESPUESTA ERROR - Agente Calendario Leraysi
// ============================================================================
// Maneja errores y devuelve respuesta estructurada al Master Agent
// ============================================================================
// NODO: FormatearRespuestaError (Code)
// INPUT: SwitchAccion (fallback/error branch)
// OUTPUT: Respuesta de error estructurada para Return
// ============================================================================

const input = $input.first().json;

// ============================================================================
// CONSTRUIR MENSAJE DE ERROR
// ============================================================================
let errorMessage = 'Error desconocido en el flujo del calendario';
let errorDetails = {};

// Error del Switch (tool no reconocida)
if (input.error) {
  errorMessage = input.error;
}

// Contexto adicional
if (input.tool) {
  errorDetails.tool_intentada = input.tool;
}

if (input.tools_validas) {
  errorDetails.tools_validas = input.tools_validas;
}

// Datos originales para debugging
if (input.original_input) {
  errorDetails.original_input = input.original_input;
}

// ============================================================================
// OUTPUT PARA MASTER AGENT
// ============================================================================
return [{
  json: {
    success: false,
    accion: 'error',
    error: errorMessage,
    detalles: errorDetails,
    mensaje_para_clienta: 'Lo siento, hubo un problema procesando tu solicitud de turno. Por favor, intenta de nuevo o contacta directamente al salón.'
  }
}];

// ============================================================================
// PARSE INPUT - Agente Calendario Leraysi
// ============================================================================
// Procesa y valida el input del Master AI Agent
// COMBINA: llm_output (del LLM) + state (de Input Main)
// Calcula duración basada en servicio + complejidad del cabello
// ============================================================================

const raw = $input.first().json;

// ============================================================================
// PASO 1: EXTRAER LLM_OUTPUT Y STATE
// ============================================================================
// El tool debe enviar:
// {
//   "llm_output": {...lo que el LLM extrajo del mensaje...},
//   "state": {...el state completo de Input Main...}
// }

// Extraer llm_output (lo que el LLM extrajo del mensaje del cliente)
const llmOutput = typeof raw.llm_output === 'string'
  ? JSON.parse(raw.llm_output)
  : (raw.llm_output || {});

const state = typeof raw.state === 'string' ? JSON.parse(raw.state) : (raw.state || {});

// ============================================================================
// PASO 2: COMBINAR LLM_OUTPUT + STATE
// ============================================================================
// llmOutput tiene prioridad (datos frescos del mensaje)
// State llena los campos que el LLM no puede extraer

const input = {
  // === Del LLM_OUTPUT (lo que el LLM extrajo del mensaje) ===
  nombre_clienta: llmOutput.nombre_clienta || state.full_name || state.nick_name,
  servicio: llmOutput.servicio || (state.servicio_interes ? [state.servicio_interes] : []),
  fecha_deseada: llmOutput.fecha_deseada || llmOutput.fecha,
  hora_deseada: llmOutput.hora_deseada || llmOutput.hora || null,
  precio: llmOutput.precio || 0,
  email: llmOutput.email || state.email || null,

  // === Del STATE (datos que el LLM no puede ver en el userPrompt) ===
  telefono: state.phone,
  clienta_id: state.lead_id,
  lead_id: state.lead_id,  // Alias para uso en tools
  lead_row_id: state.row_id,
  conversation_id: state.conversation_id,
  image_analysis: state.image_analysis || null,

  // Estado de turno existente (para reprogramación)
  turno_agendado: state.turno_agendado || false,
  turno_fecha: state.turno_fecha || null,

  // Complejidad y largo del cabello (del image_analysis)
  complejidad: state.image_analysis?.complexity || 'media',
  largo_cabello: state.image_analysis?.length || 'medio'
};

// ============================================================================
// CONFIGURACIÓN DE SERVICIOS Y DURACIONES
// ============================================================================
const SERVICIOS_CONFIG = {
  // Servicios livianos (45-60 min base)
  'Peinados': { base_min: 45, categoria: 'liviano' },
  'Manicure': { base_min: 30, categoria: 'liviano' },
  'Pedicure': { base_min: 45, categoria: 'liviano' },
  'Maquillaje': { base_min: 45, categoria: 'liviano' },
  'Corte de cabello': { base_min: 45, categoria: 'liviano' },

  // Servicios pesados (90-120 min base)
  'Alisado': { base_min: 120, categoria: 'pesado' },
  'Keratina': { base_min: 120, categoria: 'pesado' },
  'Botox capilar': { base_min: 90, categoria: 'pesado' },
  'Alisado con keratina': { base_min: 150, categoria: 'muy_pesado' },

  // Servicios de color (60-90 min base)
  'Tinte': { base_min: 90, categoria: 'pesado' },
  'Mechas': { base_min: 120, categoria: 'pesado' },
  'Balayage': { base_min: 150, categoria: 'muy_pesado' },
  'Decoloración': { base_min: 120, categoria: 'pesado' }
};

// Multiplicadores según largo del cabello
const MULTIPLICADOR_LARGO = {
  'corto': 0.8,
  'medio': 1.0,
  'largo': 1.3,
  'muy_largo': 1.5
};

// Multiplicadores según complejidad del trabajo
const MULTIPLICADOR_COMPLEJIDAD = {
  'simple': 0.9,
  'media': 1.0,
  'compleja': 1.2,
  'muy_compleja': 1.4
};

// ============================================================================
// VALIDACIÓN DE CAMPOS REQUERIDOS
// ============================================================================
const camposRequeridos = ['clienta_id', 'nombre_clienta', 'telefono', 'servicio', 'fecha_deseada', 'precio'];
const camposFaltantes = camposRequeridos.filter(campo => !input[campo]);

if (camposFaltantes.length > 0) {
  throw new Error(`[ParseInput] Campos requeridos faltantes: ${camposFaltantes.join(', ')}`);
}

// ============================================================================
// EXTRACCIÓN DE DATOS
// ============================================================================

// Datos de la clienta
const clienta_id = input.clienta_id;
const nombre_clienta = input.nombre_clienta;
const telefono = input.telefono;
const email = input.email || null;

// Datos del turno
const servicio = Array.isArray(input.servicio) ? input.servicio : [input.servicio];
const fecha_deseada = input.fecha_deseada;
const hora_deseada = input.hora_deseada || null;
const precio = Number(input.precio) || 0;

// IDs de contexto
const lead_row_id = input.lead_row_id || input.row_id;
const conversation_id = input.conversation_id || null;

// Análisis de imagen (si existe)
const image_analysis = input.image_analysis || null;
const largo_cabello = image_analysis?.length || input.largo_cabello || 'medio';
const complejidad = image_analysis?.complexity || input.complejidad || 'media';

// ============================================================================
// CÁLCULO DE DURACIÓN ESTIMADA
// ============================================================================
function calcularDuracion(servicios, largo, complejidad) {
  let duracionTotal = 0;

  for (const srv of servicios) {
    const config = SERVICIOS_CONFIG[srv];
    if (config) {
      duracionTotal += config.base_min;
    } else {
      // Servicio no mapeado, usar 60 min por defecto
      duracionTotal += 60;
    }
  }

  // Aplicar multiplicadores
  const multLargo = MULTIPLICADOR_LARGO[largo] || 1.0;
  const multComplejidad = MULTIPLICADOR_COMPLEJIDAD[complejidad] || 1.0;

  duracionTotal = Math.round(duracionTotal * multLargo * multComplejidad);

  // Redondear a múltiplos de 15 minutos
  return Math.ceil(duracionTotal / 15) * 15;
}

// Determinar categoría más pesada del servicio
function obtenerCategoriaPesada(servicios) {
  const categorias = servicios.map(srv => {
    const config = SERVICIOS_CONFIG[srv];
    return config?.categoria || 'liviano';
  });

  if (categorias.includes('muy_pesado')) return 'muy_pesado';
  if (categorias.includes('pesado')) return 'pesado';
  return 'liviano';
}

const duracion_estimada = calcularDuracion(servicio, largo_cabello, complejidad);
const categoria_servicio = obtenerCategoriaPesada(servicio);
const servicio_detalle = servicio.join(' + ');

// ============================================================================
// OUTPUT
// ============================================================================
return [{
